import kotlinx.coroutines.*

// suspend function — looks sequential, never blocks the thread
suspend fun loadUser(id: Long): User {
  delay(100)                // not blocking — schedules resume
  return api.fetchUser(id)
}

// runBlocking bridges to non-coroutine code (main, tests). Avoid in app code.
fun main() = runBlocking {
  val user = loadUser(1)
  println(user)
}

// In an Android ViewModel — use viewModelScope; cancellation tied to lifecycle.
class HomeVM : ViewModel() {
  fun load(id: Long) = viewModelScope.launch {
    val user = loadUser(id)
    _user.value = user
  }
}

// Concurrency — launch many lightweight coroutines
fun loadAll(ids: List<Long>) = viewModelScope.launch {
  val users = ids.map { id ->
    async { loadUser(id) }     // child coroutine, runs in parallel
  }.awaitAll()
  _users.value = users
}

