import kotlinx.coroutines.*

class FeedRepository {
  // Lifetime tied to this object — cancel scope when object goes away
  private val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO)

  fun warmup() {
    scope.launch {
      val main = async { api.feed() }     // child
      val sidebar = async { api.sidebar() } // child
      cache.write(main.await(), sidebar.await())
    }
  }

  fun close() { scope.cancel() }            // cancels all in-flight work
}

// coroutineScope { } — suspends until all children finish; rethrows their exceptions
suspend fun loadDashboard(): Dashboard = coroutineScope {
  val posts = async { api.posts() }
  val news = async { api.news() }
  Dashboard(posts.await(), news.await())
  // If one async throws, the other is auto-cancelled — clean up before throwing.
}

// SupervisorJob — children failures don't cancel siblings
val scope = CoroutineScope(SupervisorJob())
scope.launch { throw RuntimeException("a") }    // doesn't cancel sibling
scope.launch { delay(1000); println("alive") }

// supervisorScope { } — same idea, but bound to a coroutine block
supervisorScope {
  launch { failingTask() }
  launch { otherTask() }
}

import kotlinx.coroutines.*

suspend fun loadAndParse(url: String): Report {
  val raw: String = withContext(Dispatchers.IO) {
    URL(url).readText()                // blocking — runs on IO pool
  }
  return withContext(Dispatchers.Default) {
    parse(raw)                          // CPU-bound — runs on Default pool
  }
}

class HomeVM : ViewModel() {
  fun load(url: String) = viewModelScope.launch {  // Main by default in Android
    val report = loadAndParse(url)
    _report.value = report               // already back on Main
  }
}

