import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*

// Cold flow — runs once per collector
fun ticker(): Flow<Int> = flow {
  var i = 0
  while (currentCoroutineContext().isActive) {
    emit(i++)
    delay(1000)
  }
}

suspend fun observe() {
  ticker()
    .filter { it % 2 == 0 }
    .map { "tick #\$it" }
    .take(5)
    .collect { println(it) }
}

// Operators commonly used
fun search(query: Flow<String>): Flow<List<Result>> =
  query
    .debounce(300)
    .distinctUntilChanged()
    .filter { it.length >= 2 }
    .flatMapLatest { q -> flow { emit(api.search(q)) } } // cancel previous on new query
    .catch { emit(emptyList()) }

