// SharingStarted strategies
// - Eagerly: starts immediately, runs forever
// - Lazily: starts on first collector, never stops
// - WhileSubscribed(timeout): stops after no collectors for `timeout` ms — pairs nicely with config changes

import kotlinx.coroutines.*

// Cooperative cancellation
suspend fun longCompute() = withContext(Dispatchers.Default) {
  repeat(1_000_000) { i ->
    if (i % 1000 == 0) ensureActive()  // throws CancellationException if cancelled
    // work...
  }
}

// Cleanup that must run even on cancellation
suspend fun saveAndQuit() = coroutineScope {
  try {
    longRunning()
  } finally {
    withContext(NonCancellable) {
      flush()                          // runs even if cancelled
    }
  }
}

// Don't swallow CancellationException
suspend fun bad() {
  try {
    longRunning()
  } catch (e: Throwable) {              // ⚠️ also catches CancellationException
    log(e)
  }
}
suspend fun good() {
  try {
    longRunning()
  } catch (e: CancellationException) {
    throw e                             // re-throw
  } catch (e: Throwable) {
    log(e)
  }
}

// CoroutineExceptionHandler — for fire-and-forget at root scope
val handler = CoroutineExceptionHandler { _, e -> Logger.error(e) }
val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO + handler)

// async — exceptions on await(), not at launch
val deferred = scope.async { failingCall() }
try { deferred.await() } catch (e: Throwable) { /* handle */ }
